/**
 * Compute the
 * <a href="http://mathworld.wolfram.com/HyperbolicTangent.html" TARGET="_top">
 * hyperbolic tangent</a> of this complex number.
 * Implements the formula:
 * <pre>
 *  <code>
 *   tanh(a + bi) = sinh(2a)/(cosh(2a) + cos(2b)) + i sin(2b)/(cosh(2a) + cos(2b))
 *  </code>
 * </pre>
 * where the (real) functions on the right-hand side are
 * {@link FastMath#sin}, {@link FastMath#cos},
 * {@link FastMath#cosh} and {@link FastMath#sinh}.
 * <br/>
 * Returns {@link Complex#NaN} if either real or imaginary part of the
 * input argument is {@code NaN}.
 * <br/>
 * Infinite values in real or imaginary parts of the input may result in
 * infinite or NaN values returned in parts of the result.
 * <pre>
 *  Examples:
 *  <code>
 *   tanh(a &plusmn; INFINITY i) = NaN + NaN i
 *   tanh(&plusmn;INFINITY + bi) = &plusmn;1 + 0 i
 *   tanh(&plusmn;INFINITY &plusmn; INFINITY i) = NaN + NaN i
 *   tanh(0 + (&pi;/2)i) = NaN + INFINITY i
 *  </code>
 * </pre>
 *
 * @return the hyperbolic tangent of {@code this}.
 * @since 1.2
 */
public Complex tanh() {
    if (isNaN) {
        return NaN;
    }

    // Handle cases where real part is infinite or very large
    // When real part approaches +infinity, tanh approaches 1
    // When real part approaches -infinity, tanh approaches -1
    if (Double.isInfinite(real) && !Double.isNaN(real) && !Double.isNaN(imaginary)) {
        if (real > 0) {
            return createComplex(1.0, 0.0);
        } else {
            return createComplex(-1.0, 0.0);
        }
    }

    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;

    // For large values of real2, we need special handling to avoid overflow
    // When |real2| is very large, cosh(real2) >> cos(imaginary2)
    // So d ≈ cosh(real2), and sinh(real2)/cosh(real2) ≈ sign(real2) = ±1
    if (FastMath.abs(real2) > 20.0) { // Threshold to avoid overflow, as cosh/sinh grow exponentially
        if (real2 > 0) {
            // When real2 > 0 and large: sinh(real2)/cosh(real2) approaches 1
            // The imaginary part sin(imaginary2)/cosh(real2) approaches 0
            return createComplex(1.0, 0.0);
        } else {
            // When real2 < 0 and large: sinh(real2)/cosh(real2) approaches -1
            // The imaginary part sin(imaginary2)/cosh(real2) approaches 0
            return createComplex(-1.0, 0.0);
        }
    }

    double d = FastMath.cosh(real2) + FastMath.cos(imaginary2);

    return createComplex(FastMath.sinh(real2) / d,
                         FastMath.sin(imaginary2) / d);
}

